"use client";

/* ════════════════════════════════════════════════════════════════════════
   VelocityScatter — velocity × margin × capital (bubble) scatter.
   Port of the #scat chart in /Users/mac/Downloads/MAGELLAN UX/magellan-operations-room/06-stock-velocity.html

   X = velocity (units/day · window)
   Y = margin % (contribution)
   r = sqrt(value)·0.052 + 5    (bubble = capital at stake)
   color = ABC class (A green · B grey · C amber · D red)

   Two heat zones: money (top-right, green) and dust (bottom-left, red).
   Meaningful pulses: red on dead stock · amber on WOS<1.5 · compass on top performer.
   ════════════════════════════════════════════════════════════════════════ */

import { useMemo, useState } from "react";
import {
  VEL_ITEMS,
  CLASS_COLOR,
  TOP_PERFORMER,
  type VelItem,
} from "@/features/ops/api/ops-velocity-data";
import { useChartSize, usePrefersReducedMotion } from "@/lib/useChartSize";

export interface VelocityScatterProps {
  /** "v7" | "v30" | "v90" */
  velKey: "v7" | "v30" | "v90";
  selectedIdx: number | null;
  onSelect: (i: number) => void;
}

const PAD = { L: 8, R: 18, T: 26, B: 312 };
const X_MAX = 26;
const Y_MIN = 10;
const Y_MAX = 56;
const H = 380;
const MZx = 9, MZy = 42, DZx = 3.2, DZy = 34;

const fmtUSD = (v: number) => (v >= 1000 ? `$${Math.round(v / 1000)}K` : `$${Math.round(v)}`);

export function VelocityScatter({ velKey, selectedIdx, onSelect }: VelocityScatterProps) {
  const { ref, width } = useChartSize({ min: 640, fallback: 1000 });
  const reduced = usePrefersReducedMotion();
  const [hover, setHover] = useState<{ i: number; cx: number; cy: number; r: number } | null>(null);

  const W = Math.max(640, width);
  const SX = (v: number) => PAD.L + (v / X_MAX) * (W - PAD.L - PAD.R);
  const SY = (v: number) => PAD.B - ((v - Y_MIN) / (Y_MAX - Y_MIN)) * (PAD.B - PAD.T);
  const SR = (v: number) => Math.sqrt(v) * 0.052 + 5;

  // Largest first so small bubbles sit on top
  const sorted = useMemo(
    () => VEL_ITEMS.map((d, i) => ({ d, i })).sort((a, b) => b.d.value - a.d.value),
    [],
  );

  const star = VEL_ITEMS.find((d) => d.n === TOP_PERFORMER) ?? VEL_ITEMS[0];
  const dust = [...VEL_ITEMS].sort((a, b) => a.v30 + a.m - (b.v30 + b.m))[0];

  const dead = VEL_ITEMS.filter((d) => d.cls === "D");
  const stockoutRisk = VEL_ITEMS.filter((d) => d.wos < 1.5);

  const cornerLen = 14;
  const corner = (x: number, y: number, dx: number, dy: number) => (
    <path
      className="brk"
      d={`M${x + dx * cornerLen},${y} L${x},${y} L${x},${y + dy * cornerLen}`}
    />
  );

  const ring = (cx: number, cy: number, r0: number, r1: number, col: string, dur: number, beg: number, key: string) => (
    <circle key={key} cx={cx} cy={cy} r={r0} fill="none" stroke={col} strokeWidth={1.5}>
      <animate attributeName="r" values={`${r0};${r1}`} dur={`${dur}s`} begin={`${beg}s`} repeatCount="indefinite" />
      <animate attributeName="opacity" values="0.6;0" dur={`${dur}s`} begin={`${beg}s`} repeatCount="indefinite" />
    </circle>
  );

  const handleEnter = (i: number, cx: number, cy: number, r: number) =>
    setHover({ i, cx, cy, r });
  const handleLeave = () => setHover(null);

  const tcx = SX(star[velKey]);
  const tcy = SY(star.m);
  const tr = SR(star.value);

  return (
    <div className="scat-main-inner" ref={ref}>
      <svg id="scat" viewBox={`0 0 ${W} ${H}`} className={selectedIdx != null ? "dimmed" : ""}>
        {/* Money + dust zones */}
        <rect
          className="zone"
          x={SX(MZx)}
          y={PAD.T}
          width={W - PAD.R - SX(MZx)}
          height={SY(MZy) - PAD.T}
          fill="#1D9E75"
          stroke="#1D9E75"
        />
        <rect
          className="zone"
          x={PAD.L}
          y={SY(DZy)}
          width={SX(DZx) - PAD.L}
          height={PAD.B - SY(DZy)}
          fill="#d64545"
          stroke="#d64545"
        />

        {/* Gridlines + inside Y labels */}
        {[20, 30, 40, 50].map((v) => (
          <g key={`yl-${v}`}>
            <line className="grid" x1={PAD.L} y1={SY(v)} x2={W - PAD.R} y2={SY(v)} />
            <text className="ylab" x={PAD.L + 2} y={SY(v) - 5}>
              {v}%
            </text>
          </g>
        ))}
        <line className="base" x1={PAD.L} y1={PAD.B} x2={W - PAD.R} y2={PAD.B} />

        {/* X calibration */}
        {[0, 5, 10, 15, 20, 25].map((v) => (
          <g key={`xl-${v}`}>
            <line className="tk" x1={SX(v)} y1={PAD.B} x2={SX(v)} y2={PAD.B - 8} opacity={0.3} />
            {v < 25 &&
              [1, 2, 3, 4].map((q) => (
                <line
                  key={`xq-${v}-${q}`}
                  className="tk"
                  x1={SX(v + q)}
                  y1={PAD.B}
                  x2={SX(v + q)}
                  y2={PAD.B - 3}
                  opacity={0.1}
                />
              ))}
            <text className="xlab" x={SX(v)} y={PAD.B + 19} textAnchor="middle">
              {v}
            </text>
          </g>
        ))}

        {/* Axis titles */}
        <text className="axttl" x={W - PAD.R} y={PAD.B + 38} textAnchor="end">
          velocity · units sold / day →
        </text>
        <text className="axttl" x={PAD.L + 2} y={PAD.T - 9}>
          ↑ contribution margin
        </text>

        {/* Zone labels */}
        <text className="zlab" x={W - PAD.R - 7} y={PAD.T + 13} textAnchor="end" fill="#157a5b">
          Money zone · scale
        </text>
        <text className="zlab" x={SX(DZx) - 7} y={SY(DZy) + 13} textAnchor="end" fill="#b3322e">
          Dust · clear
        </text>

        {/* Bubbles */}
        {sorted.map((entry, idx) => {
          const { d, i } = entry;
          const cx = SX(d[velKey]);
          const cy = SY(d.m);
          const r = SR(d.value);
          const col = CLASS_COLOR[d.cls];
          const isSel = selectedIdx === i;
          return (
            <circle
              key={d.sku}
              className={`bub dotp${isSel ? " sel" : ""}`}
              cx={cx}
              cy={cy}
              r={r}
              fill={col}
              fillOpacity={0.82}
              stroke="#fff"
              strokeWidth={1}
              style={reduced ? undefined : { animationDelay: `${0.2 + idx * 0.03}s` }}
              onMouseEnter={() => handleEnter(i, cx, cy, r)}
              onMouseLeave={handleLeave}
              onClick={() => onSelect(i)}
            />
          );
        })}

        {/* Pulse rings */}
        {!reduced &&
          dead.map((d, idx) => {
            const cx = SX(d[velKey]);
            const cy = SY(d.m);
            const r = SR(d.value);
            return ring(cx, cy, r + 3, r + 16, "#d64545", 2.6, idx * 0.5, `dead-${d.sku}`);
          })}
        {!reduced &&
          stockoutRisk.map((d, idx) => {
            const cx = SX(d[velKey]);
            const cy = SY(d.m);
            const r = SR(d.value);
            return ring(cx, cy, r + 3, r + 13, "#d6a94e", 2.0, idx * 0.4, `risk-${d.sku}`);
          })}
        {!reduced && (
          <>
            {ring(tcx, tcy, tr + 5, tr + 20, "var(--compass)", 2.2, 0, "star-a")}
            {ring(tcx, tcy, tr + 5, tr + 20, "var(--compass)", 2.2, 1.1, "star-b")}
          </>
        )}
        <circle cx={tcx} cy={tcy} r={tr + 5} fill="none" stroke="var(--compass)" strokeWidth={1.5} />

        {/* Labels for star + worst dust */}
        {[
          { d: star, color: "#157a5b" },
          { d: dust, color: "#b3322e" },
        ].map(({ d, color }) => {
          if (!d) return null;
          const cx = SX(d[velKey]);
          const cy = SY(d.m);
          const r = SR(d.value);
          return (
            <text
              key={`lbl-${d.sku}`}
              className="blab"
              x={cx}
              y={cy - r - 8}
              textAnchor="middle"
              fill={color}
            >
              {d.n}
            </text>
          );
        })}

        {/* Corner brackets */}
        {corner(PAD.L, PAD.T, 1, 1)}
        {corner(W - PAD.R, PAD.T, -1, 1)}
        {corner(PAD.L, PAD.B, 1, -1)}
        {corner(W - PAD.R, PAD.B, -1, -1)}

        {/* Drop lines on hover */}
        {hover && (
          <>
            <line className="dropx" x1={hover.cx} y1={hover.cy} x2={hover.cx} y2={PAD.B} style={{ opacity: 0.8 }} />
            <line className="dropy" x1={PAD.L} y1={hover.cy} x2={hover.cx} y2={hover.cy} style={{ opacity: 0.8 }} />
            <circle cx={hover.cx} cy={hover.cy} r={hover.r + 4} fill="none" stroke="var(--compass)" strokeWidth={1.6} />
          </>
        )}

        {/* Selection ring */}
        {selectedIdx != null && (() => {
          const d = VEL_ITEMS[selectedIdx];
          if (!d) return null;
          const cx = SX(d[velKey]);
          const cy = SY(d.m);
          const r = SR(d.value);
          return <circle cx={cx} cy={cy} r={r + 5} fill="none" stroke="var(--compass)" strokeWidth={2} />;
        })()}
      </svg>

      {/* Tooltip */}
      {hover && (() => {
        const d: VelItem = VEL_ITEMS[hover.i];
        return (
          <div
            className="sc-tip"
            style={{
              display: "block",
              left: `${(hover.cx / W) * 100}%`,
              top: `${(hover.cy / H) * 100}%`,
            }}
          >
            <div className="tv">{d.n}</div>
            <div className="td">
              {d[velKey].toFixed(1)} u/day · {d.m}% margin · {fmtUSD(d.value)} · class {d.cls}
            </div>
          </div>
        );
      })()}
    </div>
  );
}
