"use client";

import { useMemo, useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { SectionLabel } from "@/components/shared/SectionLabel";
import { VelocityScatter } from "@/features/ops/components/VelocityScatter";
import { BridgePrimaryButton } from "@/features/bridge/components/BridgePrimaryButton";
import { useBridge, type BridgePage } from "@/features/bridge/hooks/use-bridge";
import {
  VEL_ITEMS,
  CLASS_LABEL,
  velocityAI,
  velocityConsole,
  type VelCategory,
  type VelVerdict,
  type VelItem,
} from "@/features/ops/api/ops-velocity-data";
import "./velocity.css";

const fmtUSD = (v: number) =>
  v >= 1000 ? `$${Math.round(v / 1000)}K` : `$${Math.round(v)}`;

const CAT_ICON: Record<VelCategory, React.ReactNode> = {
  tech: (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
      <rect x="5" y="3" width="14" height="18" rx="2" />
      <line x1="9.5" y1="18" x2="14.5" y2="18" />
    </svg>
  ),
  home: (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
      <path d="M4 11l8-6 8 6" />
      <path d="M6.5 10v9h11v-9" />
    </svg>
  ),
  lifestyle: (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
      <path d="M10 3h4v2.5l1.6 2.4V19a2 2 0 01-2 2h-3.2a2 2 0 01-2-2V7.9L10 5.5z" />
    </svg>
  ),
  accessories: (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
      <path d="M6 8.5h12l-1 11.5H7z" />
      <path d="M9 8.5a3 3 0 016 0" />
    </svg>
  ),
  stationery: (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
      <rect x="5" y="4" width="14" height="16" rx="1" />
      <line x1="9" y1="8.5" x2="15" y2="8.5" />
      <line x1="9" y1="12" x2="15" y2="12" />
    </svg>
  ),
  apparel: (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
      <path d="M8.5 4l3.5 2 3.5-2 3 3.5-2 1.8V20H7.5V9.3l-2-1.8z" />
    </svg>
  ),
};

const PERIODS = ["7 days", "30 days", "90 days"];
const VEL_KEYS = ["v7", "v30", "v90"] as const;

type VelKey = (typeof VEL_KEYS)[number];

type SortKey = "n" | "sold30" | "dsi" | "sellthru" | "gmroi" | "acc" | "wos";

const VERDICT_LABEL: Record<VelVerdict, string> = {
  reorder: "Reorder",
  watch: "Watch",
  hold: "Hold",
  liquidate: "Liquidate",
};
const VERDICT_STRIPE: Record<VelVerdict, string> = {
  reorder: "#1D9E75",
  watch: "#b88a2a",
  hold: "transparent",
  liquidate: "#d64545",
};

function reasonFor(d: VelItem): string {
  if (d.vd === "reorder")
    return `Turning fast on only ${d.wos.toFixed(1)} weeks of cover — it sells quicker than it lands. Reorder before it gaps.`;
  if (d.vd === "watch")
    return `${d.acc >= 0 ? "Accelerating " : "Easing "}${Math.abs(d.acc)}% with ${d.dsi} days on hand. Worth watching — not urgent yet.`;
  if (d.vd === "hold")
    return `${d.acc < -2 ? `Decelerating ${Math.abs(d.acc)}% and ` : ""}already ${d.dsi} days of cover. Don't deepen the position — this capital earns more in ads.`;
  return `Dead weight — ${d.dsi} days to clear at this pace. Free the ${fmtUSD(d.value)} tied up here.`;
}

export default function VelocityPage() {
  const [periodIdx, setPeriodIdx] = useState(1); // default 30 days
  const velKey: VelKey = VEL_KEYS[periodIdx];

  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [verdictFilter, setVerdictFilter] = useState<"all" | VelVerdict>("all");
  const [search, setSearch] = useState("");
  const [sortKey, setSortKey] = useState<SortKey>("sold30");
  const [sortDir, setSortDir] = useState<1 | -1>(-1);
  const [rowBridgeSent, setRowBridgeSent] = useState<number | null>(null);
  const [detailBridgeSent, setDetailBridgeSent] = useState(false);

  const accelerating = VEL_ITEMS.filter((d) => d.acc > 0).length;
  const decelerating = VEL_ITEMS.filter((d) => d.acc < 0).length;
  const maxAcc = Math.max(...VEL_ITEMS.map((d) => Math.abs(d.acc)));
  const momRows = useMemo(() => {
    return VEL_ITEMS.map((d, i) => ({ d, i })).sort((a, b) => b.d.acc - a.d.acc);
  }, []);

  const rows = useMemo(() => {
    const filtered = VEL_ITEMS.map((d, i) => ({ d, i })).filter(({ d }) => {
      if (verdictFilter !== "all" && d.vd !== verdictFilter) return false;
      if (search) {
        const q = search.toLowerCase();
        if (
          !(
            d.n.toLowerCase().includes(q) ||
            d.sku.toLowerCase().includes(q) ||
            CLASS_LABEL[d.cls].toLowerCase().includes(q)
          )
        )
          return false;
      }
      return true;
    });
    return filtered.sort((a, b) => {
      if (sortKey === "n") return a.d.n.localeCompare(b.d.n) * sortDir;
      const av = a.d[sortKey] as number;
      const bv = b.d[sortKey] as number;
      return (av - bv) * sortDir;
    });
  }, [verdictFilter, search, sortKey, sortDir]);

  const selected: VelItem | null = selectedIdx != null ? VEL_ITEMS[selectedIdx] : null;

  const handleSelect = (i: number) => {
    setSelectedIdx((cur) => (cur === i ? null : i));
    setDetailBridgeSent(false);
  };
  const handleSort = (k: SortKey) => {
    if (sortKey === k) setSortDir((d) => (d === 1 ? -1 : 1));
    else {
      setSortKey(k);
      setSortDir(k === "n" ? 1 : -1);
    }
  };
  const { openBridge } = useBridge();
  const velocityVerdictToPage: Record<VelVerdict, BridgePage> = {
    reorder: "reorder",
    watch: "watch",
    hold: "hold",
    liquidate: "liquidate",
  };
  const sendRowBridge = (i: number, verdict: VelVerdict) => {
    setRowBridgeSent(i);
    openBridge("ops", velocityVerdictToPage[verdict]);
    setTimeout(() => setRowBridgeSent(null), 1500);
  };
  const sendDetailBridge = (verdict: VelVerdict) => {
    setDetailBridgeSent(true);
    openBridge("ops", velocityVerdictToPage[verdict]);
    setTimeout(() => setDetailBridgeSent(false), 1800);
  };

  const COLS: Array<{ k: SortKey | "thumb" | "cls" | "vd"; l: string; sort: boolean; num?: boolean }> = [
    { k: "thumb", l: "", sort: false },
    { k: "n", l: "Item", sort: true },
    { k: "cls", l: "Class", sort: false },
    { k: "sold30", l: "Sold 30d", sort: true, num: true },
    { k: "dsi", l: "DSI", sort: true, num: true },
    { k: "sellthru", l: "Sell-thru", sort: true, num: true },
    { k: "gmroi", l: "GMROI", sort: true, num: true },
    { k: "acc", l: "Trend", sort: true, num: true },
    { k: "wos", l: "WOS", sort: true, num: true },
    { k: "vd", l: "Verdict", sort: false, num: true },
  ];

  const scatArgHtml =
    "Top-right is cash: <b class=\"grn\">Tee, Candle and Tote turn fast at strong margin</b> — scale them. Bottom-left is dust: <b class=\"red\">Cutlery and Mug</b> earn nothing and freeze $44K. The pulsing rings are what Magellan is flagging — amber is about to stock out, red is dead.";

  const momArgHtml =
    "Eight SKUs are speeding up and ten slowing down. The green side is where to lean in; <b>the red side is where every other tool would still tell you to buy — and you should wait.</b> Wool Beanie at −55% is a seasonal fade, not a restock cue.";

  return (
    <div className="ops-velocity-page">
      <DeptHeader
        dept="ops"
        title="Stock Velocity"
        meta={<><span className="live">Live</span> · 18 SKUs · Updated 2 min ago</>}
        actions={
          <>
            <button className="btn-util">Export</button>
            <BridgePrimaryButton dept="ops" page="liquidate">Clear slow stock → Bridge</BridgePrimaryButton>
          </>
        }
      />

      <PeriodTabs labels={PERIODS} activeIndex={periodIdx} onChange={setPeriodIdx} />

      {/* ───── Scatter chart card ───── */}
      <section className="chart-card">
        <div className="c-head">
          <div>
            <div className="c-k">Velocity × margin · bubble = capital at stake</div>
            <div className="c-hero">
              <span className="big">2.8×</span>
              <span className="d" style={{ color: "#157a5b" }}>
                portfolio GMROI · target 2.5×
              </span>
            </div>
            <div className="c-sub">
              velocity = units sold per day · last {periodIdx === 0 ? 7 : periodIdx === 1 ? 30 : 90} days
            </div>
          </div>
          <div className="cluster">
            <div className="scat-legend">
              {(["A", "B", "C", "D"] as const).map((c) => (
                <span key={c} className="sl">
                  <span
                    className="sw"
                    style={{
                      background:
                        c === "A" ? "#1D9E75" : c === "B" ? "#9a9488" : c === "C" ? "#b88a2a" : "#d64545",
                    }}
                  />
                  <span className="nm">{CLASS_LABEL[c]}</span>
                </span>
              ))}
            </div>
          </div>
        </div>

        <div className={`scat-split${selectedIdx != null ? " open" : ""}`}>
          <div className="scat-main">
            <VelocityScatter velKey={velKey} selectedIdx={selectedIdx} onSelect={handleSelect} />
          </div>
          <aside className="scat-detail">
            {!selected ? (
              <div className="sd-empty">
                <div className="ttl">Inspect a SKU</div>
                <div className="lead">
                  Click any bubble, ledger row or momentum bar to inspect an item — and send its verdict to Bridge.
                </div>
                <div className="snap">
                  <div className="sd-snap-row">
                    <span className="l">Stocked SKUs</span>
                    <span className="v">18</span>
                  </div>
                  <div className="sd-snap-row">
                    <span className="l">Capital at stake</span>
                    <span className="v">
                      {fmtUSD(VEL_ITEMS.reduce((a, d) => a + d.value, 0))}
                    </span>
                  </div>
                  <div className="sd-snap-row">
                    <span className="l">Portfolio GMROI</span>
                    <span className="v" style={{ color: "#157a5b" }}>2.8×</span>
                  </div>
                </div>
              </div>
            ) : (
              <>
                <div className="sd-head">
                  <div>
                    <div className="sd-name">{selected.n}</div>
                    <div className="sd-sku">{selected.sku} · {selected.cat}</div>
                  </div>
                  <button className="sd-clear" onClick={() => setSelectedIdx(null)}>
                    clear ✕
                  </button>
                </div>
                <div className="sd-grid">
                  <div className="sd-cell">
                    <div className="l">Velocity</div>
                    <div className="v">{selected[velKey].toFixed(1)}/d</div>
                  </div>
                  <div className="sd-cell">
                    <div className="l">Margin</div>
                    <div className="v">{selected.m}%</div>
                  </div>
                  <div className="sd-cell">
                    <div className="l">GMROI</div>
                    <div className={`v ${selected.gmroi >= 3 ? "grn" : selected.gmroi < 1.5 ? "red" : ""}`}>
                      {selected.gmroi.toFixed(1)}×
                    </div>
                  </div>
                  <div className="sd-cell">
                    <div className="l">Trend</div>
                    <div className={`v ${selected.acc > 2 ? "grn" : selected.acc < -2 ? "ops" : ""}`}>
                      {selected.acc > 0 ? "+" : ""}{selected.acc}%
                    </div>
                  </div>
                  <div className="sd-cell">
                    <div className="l">Days to sell</div>
                    <div className="v">{selected.dsi}d</div>
                  </div>
                  <div className="sd-cell">
                    <div className="l">Capital</div>
                    <div className="v">{fmtUSD(selected.value)}</div>
                  </div>
                </div>
                <div className="sd-verdict">
                  <div className="sd-vrow">
                    <span
                      className="vp"
                      style={{
                        color: {
                          reorder: "#157a5b",
                          watch: "#9a6a18",
                          hold: "var(--ink-2)",
                          liquidate: "#b3322e",
                        }[selected.vd],
                        background: {
                          reorder: "rgba(29,158,117,0.13)",
                          watch: "rgba(184,138,42,0.16)",
                          hold: "rgba(0,0,0,0.05)",
                          liquidate: "rgba(214,69,69,0.13)",
                        }[selected.vd],
                      }}
                    >
                      {selected.vd}
                    </span>
                    <span className="cl">class {selected.cls}</span>
                  </div>
                  <div className="sd-reason">{reasonFor(selected)}</div>
                  <button
                    className={`sd-bridge${detailBridgeSent ? " sent" : ""}`}
                    onClick={() => sendDetailBridge(selected.vd)}
                  >
                    {detailBridgeSent ? `${selected.vd} sent to Bridge ✓` : `${selected.vd} → Bridge`}
                  </button>
                </div>
              </>
            )}
          </aside>
        </div>

        <div className="cap-arg">
          <span className="mk" />
          <p dangerouslySetInnerHTML={{ __html: scatArgHtml }} />
        </div>
      </section>

      {/* ───── Metric strip ───── */}
      <div className="metric-strip">
        {[
          { l: "Avg turnover", v: "5.8×", s: "per year" },
          { l: "Avg days-to-sell", v: "63", s: "portfolio DSI" },
          { l: "Portfolio GMROI", v: "2.8×", s: "target 2.5×", cls: "green" },
          { l: "Dead / stale", v: VEL_ITEMS.filter((d) => d.cls === "D").length, s: "$44K frozen", cls: "red" },
          { l: "Stockout risk", v: VEL_ITEMS.filter((d) => d.wos < 1.5).length, s: "WOS < 1.5 wk", cls: "ops" },
        ].map((c, i) => (
          <div key={i} className="metric">
            <div className="metric-l">{c.l}</div>
            <div className={`metric-v ${c.cls || ""}`}>{c.v}</div>
            <div className="metric-s">{c.s}</div>
          </div>
        ))}
      </div>

      {/* ───── AI strip ───── */}
      <AIStrip label={velocityAI.label} meta={velocityAI.meta} cards={velocityAI.cards} />

      {/* ───── Momentum (diverging bars) ───── */}
      <SectionLabel>Velocity momentum — accelerating vs decelerating · 30-day change</SectionLabel>
      <section className="mom-card">
        <div className="mom-head">
          <div className="mom-split">
            <div className="mom-s">
              <span className="sv up">{accelerating}</span>
              <span className="slb">accelerating · scale</span>
            </div>
            <div className="mom-s">
              <span className="sv down">{decelerating}</span>
              <span className="slb">decelerating · hold</span>
            </div>
          </div>
          <div className="cluster">
            <div className="verified">
              <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="var(--compass)" strokeWidth="2">
                <path d="M3 17l5-5 4 3 8-9" />
                <path d="M16 6h5v5" />
              </svg>
              <div className="vt">
                <b>Decline reads as loud as growth</b>
                <span>the honest operator also says wait</span>
              </div>
            </div>
          </div>
        </div>
        <div className="mom-list">
          {momRows.map(({ d, i }) => {
            const up = d.acc >= 0;
            const w = (Math.abs(d.acc) / maxAcc) * 50;
            return (
              <div
                key={d.sku}
                className={`mom-row${selectedIdx === i ? " sel" : ""}`}
                onClick={() => handleSelect(i)}
              >
                <div className="mom-name">{d.n}</div>
                <div className="mom-track">
                  <div className="mom-mid" />
                  <div
                    className={`mom-bar ${up ? "up" : "down"}`}
                    style={{ width: `${w}%` }}
                  />
                </div>
                <div className={`mom-pct ${up ? "up" : "down"}`}>
                  {up ? "+" : ""}{d.acc}%
                </div>
              </div>
            );
          })}
        </div>
        <div className="cap-arg">
          <span className="mk" style={{ background: "var(--d-ops)" }} />
          <p dangerouslySetInnerHTML={{ __html: momArgHtml }} />
        </div>
      </section>

      {/* ───── Velocity ledger ───── */}
      <SectionLabel>Velocity ledger — class, turn &amp; return</SectionLabel>
      <div className="ldg-tools">
        <div className="pt-search">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <circle cx="11" cy="11" r="7" />
            <path d="M21 21l-4.3-4.3" />
          </svg>
          <input
            type="text"
            placeholder="Search item, SKU or class…"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
        <div className="filters">
          {(["all", "reorder", "watch", "hold", "liquidate"] as const).map((v) => (
            <button
              key={v}
              className={`fchip${verdictFilter === v ? " active" : ""}`}
              onClick={() => setVerdictFilter(v)}
            >
              {v === "all" ? "All" : v.charAt(0).toUpperCase() + v.slice(1)}
            </button>
          ))}
        </div>
      </div>

      <div className="ledger">
        <div className="ldg-head">
          {COLS.map((c, idx) => {
            if (c.k === "thumb") return <div key={idx} />;
            const active = c.sort && sortKey === c.k;
            return (
              <div
                key={idx}
                className={`th${c.num ? " num" : ""}${active ? " active" : ""}`}
                onClick={() => c.sort && handleSort(c.k as SortKey)}
                style={c.sort ? undefined : { cursor: "default" }}
              >
                {c.l}
                {c.sort && (
                  <span className="ar">{active ? (sortDir > 0 ? "▲" : "▼") : "▲"}</span>
                )}
              </div>
            );
          })}
        </div>

        {rows.length === 0 ? (
          <div className="ldg-empty">No items match this filter</div>
        ) : (
          rows.map(({ d, i }) => {
            const gcls = d.gmroi >= 3 ? "hi" : d.gmroi < 1.5 ? "lo" : "";
            const tcls = d.acc > 2 ? "up" : d.acc < -2 ? "down" : "flat";
            return (
              <div
                key={d.sku}
                className={`ldg-row${d.cls === "D" ? " dead" : ""}${selectedIdx === i ? " sel" : ""}`}
                style={{ ["--vstripe" as string]: VERDICT_STRIPE[d.vd] } as React.CSSProperties}
                onClick={() => handleSelect(i)}
              >
                <div className="inv-thumb">{CAT_ICON[d.cat]}</div>
                <div>
                  <div className="ldg-name">{d.n}</div>
                  <div className="ldg-sub">{d.sku} · {d.cat}</div>
                </div>
                <div className="cls-cell">
                  <span className={`cpill ${d.cls.toLowerCase()}`}>{CLASS_LABEL[d.cls]}</span>
                </div>
                <div className="vn">{d.sold30.toLocaleString()}</div>
                <div className={`vn${d.dsi > 300 ? " muted" : ""}`}>{d.dsi}d</div>
                <div className="vn">{d.sellthru}%</div>
                <div className={`gmroi ${gcls}`}>{d.gmroi.toFixed(1)}×</div>
                <div className={`trend ${tcls}`}>
                  {d.acc > 0 ? "+" : ""}{d.acc}%
                </div>
                <div className={`vn${d.wos > 20 ? " muted" : ""}`}>
                  {d.wos.toFixed(d.wos < 10 ? 1 : 0)}
                </div>
                <div className="ldg-verdict">
                  <span className={`vpill ${d.vd}`}>{d.vd}</span>
                </div>
                <button
                  className={`ldg-bridge${rowBridgeSent === i ? " sent" : ""}`}
                  onClick={(e) => {
                    e.stopPropagation();
                    sendRowBridge(i, d.vd);
                  }}
                >
                  {rowBridgeSent === i ? `${VERDICT_LABEL[d.vd]} sent ✓` : (
                    <>
                      {VERDICT_LABEL[d.vd]}
                      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                        <line x1="5" y1="12" x2="19" y2="12" />
                        <polyline points="12 5 19 12 12 19" />
                      </svg>
                    </>
                  )}
                </button>
              </div>
            );
          })
        )}
      </div>

      {/* ───── Console note ───── */}
      <section className="console">
        <div className="console-label">
          <span style={{ width: 18, height: 18, borderRadius: 4, background: "var(--cream)", color: "var(--navy-deep)", display: "inline-flex", alignItems: "center", justifyContent: "center", fontFamily: "Inter", fontSize: 11, fontWeight: 600 }}>
            M
          </span>
          Console note
        </div>
        <div className="console-row">
          <div className="console-tag read">Read</div>
          <div className="console-body" dangerouslySetInnerHTML={{ __html: velocityConsole.read }} />
        </div>
        <div className="console-row">
          <div className="console-tag exposure">Exposure</div>
          <div className="console-body" dangerouslySetInnerHTML={{ __html: velocityConsole.exposure }} />
        </div>
        <div className="console-row">
          <div className="console-tag directive">Directive</div>
          <div className="console-body" dangerouslySetInnerHTML={{ __html: velocityConsole.directive }} />
        </div>
      </section>
    </div>
  );
}
