/**
 * Mock data for the Operations · Stock Velocity sub-page.
 * Each item has multi-window velocities (7/30/90), GMROI, ABC class, and a
 * verdict (reorder/watch/hold/liquidate) plus a 30-day acceleration % (acc).
 *
 * Derived per-item:
 *   value   — qty * landed (USD at cost)
 *   dsi     — days to sell at v30
 *   sold30  — units sold last 30 days = round(v30 * 30)
 *   sellthru — sold / (sold + onhand) %
 *   wos     — weeks of stock at v30
 */

export type VelClass = "A" | "B" | "C" | "D";
export type VelVerdict = "reorder" | "watch" | "hold" | "liquidate";
export type VelCategory = "tech" | "home" | "lifestyle" | "accessories" | "stationery" | "apparel";

export interface VelItemRaw {
  n: string;
  sku: string;
  cat: VelCategory;
  qty: number;
  /** USD landed cost per unit */
  landed: number;
  /** Margin % */
  m: number;
  /** velocity per day, last 30 / 7 / 90 days */
  v30: number;
  v7: number;
  v90: number;
  gmroi: number;
  cls: VelClass;
  vd: VelVerdict;
  /** 30-day acceleration % (positive = speeding up) */
  acc: number;
}

export interface VelItem extends VelItemRaw {
  /** Inventory value at landed cost (USD) */
  value: number;
  /** Days to sell at v30 */
  dsi: number;
  /** Units sold last 30 days */
  sold30: number;
  /** Sell-through % */
  sellthru: number;
  /** Weeks of stock */
  wos: number;
}

