export const VEL_ITEMS: VelItem[] = RAW.map((d) => {
  const value = d.qty * d.landed;
  const dsi = Math.round(d.qty / d.v30);
  const sold30 = Math.round(d.v30 * 30);
  const sellthru = Math.round((sold30 / (sold30 + d.qty)) * 100);
  const wos = d.qty / d.v30 / 7;
  return { ...d, value, dsi, sold30, sellthru, wos };
});

